import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithTrailingDelimiterTrue() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat modified = original.withTrailingDelimiter(true);
        assertNotNull(modified);
        assertTrue(modified.getTrailingDelimiter());
        // Original should remain unchanged
        assertFalse(original.getTrailingDelimiter());
    }

    @Test
    void testWithTrailingDelimiterFalse() {
        CSVFormat original = CSVFormat.DEFAULT.withTrailingDelimiter(true);
        CSVFormat modified = original.withTrailingDelimiter(false);
        assertNotNull(modified);
        assertFalse(modified.getTrailingDelimiter());
        // Original should remain unchanged
        assertTrue(original.getTrailingDelimiter());
    }

    @Test
    void testWithTrailingDelimiterDoesNotAffectOtherFields() {
        CSVFormat original = CSVFormat.DEFAULT
                .withDelimiter(';')
                .withQuote('\'')
                .withIgnoreEmptyLines(false)
                .withNullString("NULL")
                .withSkipHeaderRecord(true)
                .withTrim(true)
                .withAutoFlush(true);

        CSVFormat modified = original.withTrailingDelimiter(true);

        assertEquals(original.getDelimiter(), modified.getDelimiter());
        assertEquals(original.getQuoteCharacter(), modified.getQuoteCharacter());
        assertEquals(original.getIgnoreEmptyLines(), modified.getIgnoreEmptyLines());
        assertEquals(original.getNullString(), modified.getNullString());
        assertEquals(original.getSkipHeaderRecord(), modified.getSkipHeaderRecord());
        assertEquals(original.getTrim(), modified.getTrim());
        assertEquals(original.getAutoFlush(), modified.getAutoFlush());

        // Trailing delimiter is changed only in modified
        assertFalse(original.getTrailingDelimiter());
        assertTrue(modified.getTrailingDelimiter());
    }
}
